import numpy as np

def sigmoid(z):
    return 1 / (1 + np.exp(-z))

def d_sigmoid(z):
    s = sigmoid(z)
    return s * (1 - s)

print(sigmoid(0.0), d_sigmoid(0.0))   # 0.5  0.25 (the peak)

import numpy as np

def softmax(z):
    z = z - np.max(z)            # stability: avoid overflow
    e = np.exp(z)
    return e / e.sum()

print(softmax(np.array([2.0, 1.0, 0.1])))  # sums to 1.0

